'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { Home, LayoutDashboard, Layers, BookOpen, User, Compass, Calculator, Brain, Palette, FileText, Leaf } from 'lucide-react';

// Sidebar navigation items
const sidebarLinks = [
  { label: 'Home', href: '/', icon: Home },
  { label: 'Dashboard', href: '/dashboard', icon: LayoutDashboard },
  { label: 'Farm Data Entry', href: '/farm', icon: FileText },
  { label: 'Custom Model Builder', href: '/custom-model', icon: Layers },
  { label: 'Strata System', href: '/strata', icon: Layers },
  { label: 'Designer', href: '/designer', icon: Compass },
  { label: 'Predict', href: '/predict', icon: Brain },
  { label: 'Optimizer', href: '/optimize', icon: Palette },
  { label: 'Crops', href: '/crops', icon: Leaf },
  { label: 'Calculator', href: '/calc', icon: Calculator },
  { label: 'Success Stories', href: '/research', icon: BookOpen },
  { label: 'Docs', href: '/docs', icon: FileText },
];

export default function Sidebar() {
  const pathname = usePathname();

  return (
    <aside className="w-56 bg-[#1B4332] min-h-screen flex flex-col fixed left-0 top-0 bottom-0 z-40">
      {/* Logo */}
      <div className="p-4 border-b border-green-800">
        <Link href="/" className="flex items-center gap-2">
          <span className="text-green-400 text-2xl">🌿</span>
          <span className="text-white font-bold text-xl">MultiSow</span>
        </Link>
      </div>

      {/* Navigation */}
      <nav className="flex-1 py-4 overflow-y-auto">
        {sidebarLinks.map((link) => {
          const Icon = link.icon;
          const isActive = pathname === link.href;
          return (
            <Link
              key={link.href}
              href={link.href}
              className={`flex items-center gap-3 px-4 py-3 mx-2 rounded-lg transition-colors ${
                isActive
                  ? 'bg-green-700/50 text-white'
                  : 'text-green-100/70 hover:bg-green-700/30 hover:text-white'
              }`}
            >
              <Icon size={20} />
              <span className="font-medium">{link.label}</span>
            </Link>
          );
        })}
      </nav>

      {/* Login button at bottom */}
      <div className="p-4 border-t border-green-800">
        <Link
          href="/login"
          className="flex items-center gap-3 px-4 py-3 text-green-100/70 hover:bg-green-700/30 hover:text-white rounded-lg transition-colors"
        >
          <User size={20} />
          <span className="font-medium">Login</span>
        </Link>
      </div>
    </aside>
  );
}
